const hre = require("hardhat");

async function main() {
  const Voting = await hre.ethers.getContractFactory("Voting");
  const voting = await Voting.deploy(); // Deploy contract

  await voting.waitForDeployment(); // ✅ Correct function

  console.log("Voting contract deployed at:", voting.target); // ✅ Correct way to log the address
}

main().catch((error) => {
  console.error(error);
  process.exitCode = 1;
});
